);

-- Keep consistency for manual rows linked to own batches
ALTER POLICY manual_rows_select
ON public.manual_import_rows
USING (
  hub_is_admin()
  OR EXISTS (
    SELECT 1
    FROM public.manual_import_batches b
    WHERE b.id = manual_import_rows.batch_id
      AND (
        hub_user_has_area(b.area_id)
        OR b.imported_by = auth.uid()
      )
